UPDATE "file_resource"
SET "reserved_conversation_id" = #{conversationId},
    "reserved_request_id" = #{requestId},
    "reserved_until" = NOW() + (#{reservationSeconds} * INTERVAL '1 second'),
    "modifier_id" = #{userId}
WHERE "creator_id" = #{userId}
  AND "deleted" = FALSE
  AND "confirmed_time" IS NOT NULL
  AND "status" IN ('VALIDATING', 'PROCESSING', 'READY', 'FAILED')
  AND (
      "reserved_until" IS NULL
      OR "reserved_until" < NOW()
      OR "reserved_conversation_id" = #{conversationId}
  )
  AND "file_id" IN

    #{fileId}

UPDATE "file_resource"
SET "status" = 'PROCESSING',
    "status_revision" = "status_revision" + 1,
    "modifier_id" = #{userId}
WHERE "id" = #{id}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE
  AND "status" = 'VALIDATING'

UPDATE "file_resource"
SET "status" = 'FAILED',
    "status_revision" = "status_revision" + 1,
    "modifier_id" = #{userId},
    "error_code" = #{errorCode},
    "error_message" = #{errorMessage}
WHERE "id" = #{id}
  AND "creator_id" = #{userId}
  AND "deleted" = FALSE
  AND "status" IN ('VALIDATING', 'PROCESSING')
